  ('elementary-8b44517b-moex-00357', 'elementary-8b44517b', 'elementary-8b44517b-moex-113-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '公共設施因設置管理有欠缺，致人民權利受有損害者，構成國家賠償法第3條第1項之國家賠償責任。 有關該責任之敘述，下列何者正確？', '["設置或管理機關得以主張於防止損害之發生已盡相當之注意而免責", "所損害之法益限於生命、身體、人身自由、財產四者", "公立動物園所飼養的動物，非屬本條所稱之公共設施", "僅限於故意或重大過失造成之損害方有賠償責任"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:31+00:00", "source_pdf_sha1": "4cff5c1bfc40", "answer_pdf_sha1": "f53769d74470", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00358', 'elementary-8b44517b', 'elementary-8b44517b-moex-113-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '建築物所有人依建築法規定應維護建築物合法使用，因此，在出租房屋時，房客變更房屋防火設計時，所 有人亦應負責。對此一行政上責任的定性，下列何者正確？', '["無過失責任", "行為責任", "狀態責任", "代履行責任"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:31+00:00", "source_pdf_sha1": "4cff5c1bfc40", "answer_pdf_sha1": "f53769d74470", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00359', 'elementary-8b44517b', 'elementary-8b44517b-moex-113-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '一行為違反數個行政法上義務規定而應處罰鍰者，下列敘述何者錯誤？', '["依法定罰鍰額最高之規定裁處", "裁處之額度，不得低於各該規定之罰鍰最低額", "除應處罰鍰外，另有沒入或其他種類行政罰之處罰者，得依該規定併為裁處", "一行為違反社會秩序維護法而應受處罰，如已裁處拘留者，得再裁處罰鍰"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:31+00:00", "source_pdf_sha1": "4cff5c1bfc40", "answer_pdf_sha1": "f53769d74470", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00360', 'elementary-8b44517b', 'elementary-8b44517b-moex-113-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '甲一行為同時違反A法及B法，A法規定應裁處新臺幣（下同）10萬元以下，3萬元以上罰鍰，B法規 定應裁處5萬元以下，1萬元以上罰鍰。下列主管機關之裁處，何者錯誤？', '["得裁處最高10萬元罰鍰", "得裁處10萬元以下，1萬元以上罰鍰", "罰鍰不得低於1萬元", "A法及B法分別處罰"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:31+00:00", "source_pdf_sha1": "4cff5c1bfc40", "answer_pdf_sha1": "f53769d74470", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 20, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00361', 'elementary-8b44517b', 'elementary-8b44517b-moex-113-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '人民不服行政處分，要提起行政訴訟前，依法原則上應提起何種程序？', '["請願", "陳情", "申訴", "訴願"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:31+00:00", "source_pdf_sha1": "4cff5c1bfc40", "answer_pdf_sha1": "f53769d74470", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00362', 'elementary-8b44517b', 'elementary-8b44517b-moex-113-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '有關訴願制度目的及運作的敘述，下列何者錯誤？', '["實踐憲法上人民之訴願權", "維護人民權益", "人民不服經聽證程序所為之行政處分，應先提起訴願，再提起行政訴訟", "係屬行政機關自我審查之機制"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:31+00:00", "source_pdf_sha1": "4cff5c1bfc40", "answer_pdf_sha1": "f53769d74470", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00363', 'elementary-8b44517b', 'elementary-8b44517b-moex-113-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '下列何者非屬私經濟行政之範疇？', '["消防局依採購契約給付救災設備之價金", "勞工局提供就業之相關資訊", "自來水公司向用戶收取水費", "監理處標售車牌"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:31+00:00", "source_pdf_sha1": "4cff5c1bfc40", "answer_pdf_sha1": "f53769d74470", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00364', 'elementary-8b44517b', 'elementary-8b44517b-moex-113-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '人民提起下列何種類型之行政訴訟，應先踐行訴願程序？', '["確認訴訟及一般給付訴訟", "課予義務訴訟及確認訴訟", "撤銷訴訟及課予義務訴訟", "課予義務訴訟及一般給付訴訟"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:31+00:00", "source_pdf_sha1": "4cff5c1bfc40", "answer_pdf_sha1": "f53769d74470", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00365', 'elementary-8b44517b', 'elementary-8b44517b-moex-113-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '下列關於簡易訴訟上訴程序之敘述，何者正確？', '["對於簡易程序之第一審判決，得上訴於管轄之地方法院，其審判以獨任行之", "對於簡易訴訟程序之第二審判決，當事人得逕向最高法院提起上訴，無上訴利益額數之限制", "對於簡易訴訟程序之第二審判決，提起第三審上訴，不須經原裁判法院之許可", "簡易訴訟程序第三審之性質，為法律審"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:31+00:00", "source_pdf_sha1": "4cff5c1bfc40", "answer_pdf_sha1": "f53769d74470", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00366', 'elementary-8b44517b', 'elementary-8b44517b-moex-113-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '下列關於民事訴訟當事人能力之敘述，何者正確？', '["關於遺產分割訴訟，得列同為繼承人之胎兒為被告，除非將來胎兒係死產，否則胎兒具當事人能力", "公寓大廈管理委員會無當事人能力，不得作為訴訟上之原告", "獨資商號具有當事人能力，得作為民事訴訟之當事人", "若原告於訴訟進行中死亡，法院應逕以原告無當事人能力，裁定駁回原告之訴"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:31+00:00", "source_pdf_sha1": "4cff5c1bfc40", "answer_pdf_sha1": "f53769d74470", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL)
